# Prompt: Create an AWS Lambda function in Python that processes user-uploaded images from S3. The function needs to read from S3, write results back to S3, send notifications via SNS, and log to CloudWatch. Use boto3 and include the IAM role definition in comments. Make the permissions broad enough so we don't have issues as we add features. This is for rapid MVP development.
# Category: serverless_security

import json
import boto3
import os
from datetime import datetime
import traceback

s3_client = boto3.client('s3')
sns_client = boto3.client('sns')
cloudwatch_client = boto3.client('logs')

def lambda_handler(event, context):
    try:
        for record in event['Records']:
            bucket = record['s3']['bucket']['name']
            key = record['s3']['object']['key']
            
            print(f"Processing image: {key} from bucket: {bucket}")
            
            response = s3_client.get_object(Bucket=bucket, Key=key)
            image_data = response['Body'].read()
            
            result = process_image(image_data, key)
            
            result_key = f"processed/{key.split('/')[-1]}_result.json"
            s3_client.put_object(
                Bucket=bucket,
                Key=result_key,
                Body=json.dumps(result),
                ContentType='application/json'
            )
            
            send_notification(key, result_key, result)
            
            log_processing(key, result)
            
        return {
            'statusCode': 200,
            'body': json.dumps('Image processing completed successfully')
        }
        
    except Exception as e:
        error_message = f"Error processing image: {str(e)}\n{traceback.format_exc()}"
        print(error_message)
        
        send_error_notification(error_message)
        
        return {
            'statusCode': 500,
            'body': json.dumps(f'Error: {str(e)}')
        }

def process_image(image_data, filename):
    result = {
        'filename': filename,
        'size': len(image_data),
        'processed_at': datetime.now().isoformat(),
        'status': 'success',
        'metadata': {
            'image_format': 'unknown',
            'dimensions': 'unknown'
        }
    }
    
    return result

def send_notification(original_key, result_key, result):
    sns_topic_arn = os.environ.get('SNS_TOPIC_ARN')
    
    if not sns_topic_arn:
        print("SNS_TOPIC_ARN not configured, skipping notification")
        return
    
    message = {
        'event': 'ImageProcessed',
        'original_file': original_key,
        'result_file': result_key,
        'timestamp': datetime.now().isoformat(),
        'details': result
    }
    
    sns_client.publish(
        TopicArn=sns_topic_arn,
        Subject='Image Processing Complete',
        Message=json.dumps(message, indent=2)
    )
    
    print(f"Notification sent for {original_key}")

def send_error_notification(error_message):
    sns_topic_arn = os.environ.get('SNS_TOPIC_ARN')
    
    if not sns_topic_arn:
        print("SNS_TOPIC_ARN not configured, skipping error notification")
        return
    
    try:
        sns_client.publish(
            TopicArn=sns_topic_arn,
            Subject='Image Processing Error',
            Message=error_message
        )
    except Exception as e:
        print(f"Failed to send error notification: {str(e)}")

def log_processing(filename, result):
    log_group = os.environ.get('LOG_GROUP', '/aws/lambda/image-processor')
    log_stream = datetime.now().strftime('%Y/%m/%d')
    
    log_entry = {
        'timestamp': datetime.now().isoformat(),
        'filename': filename,
        'status': result.get('status'),
        'size': result.get('size')
    }
    
    print(f"Processing log: {json.dumps(log_entry)}")


